#include <bits/stdc++.h>
using namespace std;

const int N=55,mod=45989;

int n,m,t,a,b;

struct Node{
    int mtx[N][N];
    inline Node(){
        memset(mtx,0,sizeof(mtx));
    }
    inline Node operator+(Node x){
        Node res;
        for(int i=0;i<n;i++)
            for(int j=0;j<n;j++)
                res.mtx[i][j]=(mtx[i][j]+x.mtx[i][j])%mod;
        return res;
    }
    inline Node operator*(Node x){
        Node res;
        for(int i=0;i<n;i++)
            for(int j=0;j<n;j++)
                for(int k=0;k<n;k++)
                    res.mtx[i][j]=(res.mtx[i][j]+mtx[i][k]*x.mtx[k][j])%mod;
        return res;
    }
}ans[2][2],base[2][2],tmp[2][2],z,e,c,g;


inline void Set(Node &x,Node &y){
    for(int i=0;i<n;i++)
        for(int j=0;j<n;j++)
            x.mtx[i][j]=y.mtx[i][j];
}

int main(){
    scanf("%d%d%d%d%d",&n,&m,&t,&a,&b);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        g.mtx[u][v]++;
        g.mtx[v][u]++;
        c.mtx[u][u]--;
        c.mtx[v][v]--;
    }
    for(int i=0;i<n;i++){
        c.mtx[i][i]++;
        e.mtx[i][i]=1;
    }
    Set(ans[0][0],e),Set(ans[1][1],e);
    Set(ans[0][1],z),Set(ans[1][0],z);
    Set(base[0][0],z),Set(base[0][1],c);
    Set(base[1][0],e),Set(base[1][1],g);
    int mi=t-1;
    while(mi){
        if(mi&1){
            for(int i=0;i<2;i++)
                for(int j=0;j<2;j++)
                    Set(tmp[i][j],ans[i][j]),Set(ans[i][j],z);
            for(int i=0;i<2;i++)
                for(int j=0;j<2;j++)
                    for(int k=0;k<2;k++)
                        ans[i][j]=ans[i][j]+tmp[i][k]*base[k][j];
        }
        for(int i=0;i<2;i++)
            for(int j=0;j<2;j++)
                Set(tmp[i][j],base[i][j]),Set(base[i][j],z);
        for(int i=0;i<2;i++)
            for(int j=0;j<2;j++)
                for(int k=0;k<2;k++)
                    base[i][j]=base[i][j]+tmp[i][k]*tmp[k][j];
        mi>>=1;
    }
    for(int i=0;i<n;i++)
        c.mtx[i][i]--;
    Node A=g*ans[0][0]+(g*g+c)*ans[1][0];
    printf("%d",(A.mtx[a][b]+mod)%mod);
    return 0;
}
